import React, { useState } from "react";
import CalendarGrid from "./CalendarGrid";
import eventsData from "../data/events";
import "./Calendar.css";

function Calendar() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewMode, setViewMode] = useState("month");

  const [activeFilters, setActiveFilters] = useState({
    holiday: true,
    leave: true,
    birthday: true,
  });

  const handlePrev = () => {
    const newDate = new Date(currentDate);
    if (viewMode === "month") {
      newDate.setMonth(newDate.getMonth() - 1);
    } else {
      newDate.setDate(newDate.getDate() - 7);
    }
    setCurrentDate(newDate);
  };

  const handleNext = () => {
    const newDate = new Date(currentDate);
    if (viewMode === "month") {
      newDate.setMonth(newDate.getMonth() + 1);
    } else {
      newDate.setDate(newDate.getDate() + 7);
    }
    setCurrentDate(newDate);
  };

  const toggleFilter = (type) => {
    setActiveFilters((prev) => ({
      ...prev,
      [type]: !prev[type],
    }));
  };

  return (
    <div className="calendar-page">
      {/* FILTER SIDEBAR */}
      <div className="calendar-filters">
        <h3 className="filter-title">Filters</h3>

        <label className="filter-item">
          <input
            type="checkbox"
            checked={activeFilters.holiday}
            onChange={() => toggleFilter("holiday")}
          />
          <span>Holidays (Green)</span>
        </label>

        <label className="filter-item">
          <input
            type="checkbox"
            checked={activeFilters.leave}
            onChange={() => toggleFilter("leave")}
          />
          <span>Leaves (Yellow)</span>
        </label>

        <label className="filter-item">
          <input
            type="checkbox"
            checked={activeFilters.birthday}
            onChange={() => toggleFilter("birthday")}
          />
          <span>Birthdays (Blue)</span>
        </label>
      </div>

      {/* MAIN CALENDAR */}
      <div className="calendar-main">
        {/* HEADER */}
        <div className="calendar-header">
          <button
            className={`nav-btn ${viewMode === "month" ? "active" : ""}`}
            onClick={() => setViewMode("month")}
          >
            Month
          </button>

          <div className="center-controls">
            <button className="nav-btn small" onClick={handlePrev}>
              Prev
            </button>

            <h3 className="month-year">
              {currentDate.toLocaleString("default", {
                month: "long",
                year: "numeric",
              })}
            </h3>

            <button className="nav-btn small" onClick={handleNext}>
              Next
            </button>
          </div>

          <button
            className={`nav-btn ${viewMode === "week" ? "active" : ""}`}
            onClick={() => setViewMode("week")}
          >
            Week
          </button>
        </div>

        {/* GRID */}
        <CalendarGrid
          currentDate={currentDate}
          events={eventsData}
          activeFilters={activeFilters}
          viewMode={viewMode}
        />
      </div>
    </div>
  );
}

export default Calendar;
